.darma-loader-darma-custom-017 {
  width: 40px;
  aspect-ratio: 1;
  border-radius: 50%;
  margin-top: -30px;
  display: flex;
  justify-content: center;
  overflow: hidden;
  transform-origin: 50% 116.5%;
  animation: darma-loader-darma-custom-017-l17 2s infinite linear;
}
.darma-loader-darma-custom-017::before {
  content: "";
  min-width: 233%;
  height: 233%;
  background: radial-gradient(farthest-side, var(--loader-color, #00DA3C) 90%, #0000) top, radial-gradient(farthest-side, var(--loader-secondary-color, #00CBE7) 90%, #0000) left, radial-gradient(farthest-side, #FD8603 90%, #0000) bottom, radial-gradient(farthest-side, #F4F328 90%, #0000) right;
  background-size: 43% 43%;
  background-repeat: no-repeat;
  animation: inherit;
  animation-direction: reverse;
}
@keyframes darma-loader-darma-custom-017-l17 {
  100% { transform: rotate(360deg); }
}

